===== crawl.js =====
'use strict';
/**
 * crawl.js - the P3 evidence crawler entry. Produces the EvidenceBundle.corpus the pure facts layer
 * consumes ({pages:[{url,title,text,jsonLd,ogSiteName?}], footerText?}) plus a coverage report.
 *
 * ALL network + clock effects are INJECTED so node:test runs offline and deterministically:
 *   crawl(domain, { fetchFn, deadlineMs, maxPages, width, now, timers, fetchXml, log, sector, rules,
 *                   followDocuments }) -> { domain, corpus, unreachable, reason, documents, coverage,
 *                   telemetry, notes }
 *   fetchFn(url) -> Promise<{ ok, status, body, finalUrl?, contentType? }>   (the ONLY way bytes arrive)
 *
 * Doctrine preserved:
 *   - E-236 parallelism: parallel page fetches (width from opts, NO floor), parallel sitemap discovery,
 *     TIER-1-first ordering applied BEFORE the page cap (discover.js).
 *   - Rule 9: every fetch is wrapped in a hard Promise.race deadline (pool.withDeadline); the pool's
 *     wall-clock deadline is a CAP, never a floor (Rule 8).
 *   - C-024/C-025: the corpus char cap is generous and env-guarded - a sub-floor env value THROWS.
 *   - C-031/C-032/C-038: a login/challenge/error/SPA-shell response never enters the corpus or flips
 *     reachability; an unreadable site yields an unreachable bundle (nothing asserted).
 *   - C-033/C-034: the homepage footer is a mandatory surface, and footer-linked documents are followed
 *     (evidence/documents), with unparsed PDFs demoting dependent obligations in the coverage report.
 */

const crypto = require('crypto');
const safeFetch = require('../../tools/lib/safe-fetch.js');
const { withDeadline, runPool } = require('./pool.js');
const extract = require('./extract.js');
const discover = require('./discover.js');
const coverage = require('./coverage-contract.js');
const { collectDocuments, isPdfLike } = require('../documents/documents.js');

const CORPUS_CAP_FLOOR = 50000;      // below this, footer disclosures fall past the cut (russell-cooke, C-024)
const CORPUS_CAP_DEFAULT = 500000;
const PAGES_FLOOR = 5;
const PAGES_DEFAULT = 120;
const WIDTH_DEFAULT = 8;
const DEADLINE_DEFAULT = 45000;

// resolveCap(envName, def, floor) -> the effective cap. An env value below the safety floor THROWS
// (caution.md C-025: a budget must never be silently zeroed to nothing via env).
function resolveCap(envName, def, floor) {
  const raw = process.env[envName];
  if (raw === undefined || raw === '') return def;
  const n = Number(raw);
  if (!Number.isFinite(n) || n < floor) {
    throw new Error(envName + '=' + JSON.stringify(raw) + ' is below the safety floor of ' + floor + '; a corpus budget is a cap, never a silent zeroing (caution.md C-025)');
  }
  return n;
}

// normaliseDomain(domain) -> the canonical host for a raw operator-supplied domain, produced through the
// ONE host door (safe-fetch.inputHost): scheme/path/port/www are parsed off via `new URL`, never string-
// stripped here (the second-door class, Rule 1). Returns '' when no host can be parsed.
function normaliseDomain(domain) {
  return safeFetch.inputHost(domain);
}

// fetchPage(fetchFn, url, perPageMs, timers) -> the fetch result, or null on failure/timeout (Rule 9:
// a slow page degrades to null and the crawl continues; it never hangs).
async function fetchPage(fetchFn, url, perPageMs, timers) {
  try { return await withDeadline(() => fetchFn(url), perPageMs, timers); }
  catch (e) { return null; /* FAIL-OPEN: a per-page deadline/exception yields a null slot handled by the caller's telemetry, never a hang or a swallowed hard error. */ }
}

// makeFetchXml(fetchFn, perPageMs, timers) -> the injected XML/robots fetcher discover.js needs: returns
// the body text on a 200, '' otherwise (never throws), each read behind the same hard deadline.
function makeFetchXml(fetchFn, perPageMs, timers) {
  return (url) => fetchPage(fetchFn, url, perPageMs, timers).then((r) => (r && r.ok && r.body) ? String(r.body) : '');
}

// contentPageFrom(url, res, cap) -> a corpus page ({url,title,text,jsonLd,ogSiteName?}) when res is real,
// readable CONTENT (not a login/challenge/error/shell, C-031/C-038); else null with the reason class. A
// document asset (PDF/doc, by extension or content-type) is NOT an HTML corpus page: its binary bytes
// would strip into pseudo-"content" and falsely cover a page-class, defeating the C-033 no-parser
// interlock. It is deferred to the documents lane and marked 'document' here (never asserted from).
function contentPageFrom(url, res, cap) {
  if (!res || !res.body) return { page: null, klass: res && res.status ? 'error' : 'unreachable' };
  if (isPdfLike(url, res.contentType)) return { page: null, klass: 'document' };
  const klass = extract.pageContentClass(res.status, res.body);
  if (klass !== 'content') return { page: null, klass };
  const page = extract.buildPage(res.finalUrl || url, res.body);
  let truncated = false;
  if (page.text.length > cap) { truncated = true; page.text = page.text.slice(0, cap); }
  return { page, klass: 'content', truncated, bodyHash: crypto.createHash('sha1').update(String(res.body)).digest('hex') };
}

// accumulateCorpus(fetchList, results, home, homeUrl, cap) -> { pages, truncated, telemetry }. Content
// pages are deduped by body hash (soft-404s collapse); every non-content class is counted, never asserted.
function accumulateCorpus(fetchList, results, cap) {
  const pages = [];
  const seenBody = new Set();
  const telemetry = { pages_tried: fetchList.length, content: 0, login: 0, challenge: 0, error: 0, empty: 0, unreachable: 0 };
  let truncated = false;
  for (let i = 0; i < fetchList.length; i++) {
    const { page, klass, truncated: t, bodyHash } = contentPageFrom(fetchList[i], results[i], cap);
    telemetry[klass] = (telemetry[klass] || 0) + 1;
    if (!page) continue;
    if (seenBody.has(bodyHash)) continue;
    seenBody.add(bodyHash);
    truncated = truncated || Boolean(t);
    pages.push(page);
  }
  return { pages, truncated, telemetry };
}

// footerLinks(homeHtml, base, accepted) -> same-site hrefs found inside the homepage <footer> (where the
// policy/PDF links live, C-034); empty when there is no footer region.
function footerLinks(homeHtml, base, accepted) {
  const m = /<footer\b[^>]*>([\s\S]*?)<\/footer\s*>/i.exec(String(homeHtml || ''));
  if (!m) return [];
  return discover.discoverLinks(m[1], base, accepted);
}

// blockReason(homeRes, homeKlass, pageCount) -> an honest reason string when the crawl read no content.
function blockReason(homeRes, homeKlass, pageCount) {
  if (pageCount > 0) return null;
  if (homeKlass === 'challenge') return 'anti_bot_challenge';
  if (homeKlass === 'login') return 'login_wall';
  if (homeRes && homeRes.status >= 400) return 'http_' + homeRes.status;
  if (homeKlass === 'empty') return 'js_rendered_empty_shell';
  return 'no_readable_pages';
}

// buildCoverage(pages, opts, truncated, unparsedClasses) -> the coverage report: the site-level render
// class always, plus the per-rule covered|screened contract when catalogue rules were supplied.
function buildCoverage(pages, opts, truncated, unparsedClasses) {
  const site = coverage.computeCoverage(pages, opts.sector);
  const out = { site };
  if (Array.isArray(opts.rules)) out.perRule = coverage.coverageFor(opts.rules, pages, { truncated, unparsedClasses });
  return out;
}

// makeRecorder(opts) -> { notes, record }. record(kind,msg) appends a typed note AND forwards to the
// injected log, so a degraded lane is always recorded and never silent (Rule 4).
function makeRecorder(opts) {
  const notes = [];
  const log = typeof opts.log === 'function' ? opts.log : () => {};
  const record = (kind, msg) => { notes.push({ kind, msg }); log(kind, msg); };
  return { notes, record };
}

// resolveBudgets(opts) -> the effective crawl budgets, each an upper bound (Rule 8): the corpus char cap,
// the page cap, the pool width, the wall-clock deadline and the per-page deadline. Env caps below their
// safety floor THROW via resolveCap (C-025); nothing here floors a budget.
function resolveBudgets(opts) {
  const cap = typeof opts.corpusMaxChars === 'number' ? opts.corpusMaxChars : resolveCap('CORPUS_MAX_CHARS', CORPUS_CAP_DEFAULT, CORPUS_CAP_FLOOR);
  const maxPages = typeof opts.maxPages === 'number' ? opts.maxPages : resolveCap('MAX_CRAWL_PAGES', PAGES_DEFAULT, PAGES_FLOOR);
  const width = typeof opts.width === 'number' && opts.width > 0 ? opts.width : WIDTH_DEFAULT;
  const deadlineMs = typeof opts.deadlineMs === 'number' ? opts.deadlineMs : DEADLINE_DEFAULT;
  const perPageMs = Math.min(deadlineMs, opts.perPageMs || 20000);
  return { cap, maxPages, width, deadlineMs, perPageMs };
}

// fetchHomepage(ctx) -> { home, homeHtml, homeKlass }. The homepage is the one mandatory surface (footer
// disclosures live here, C-034); a non-content homepage (login/challenge/error/SPA shell) is recorded and
// never asserted from (C-031/C-038). ctx carries the shared crawl context (opts, base, perPageMs, record).
async function fetchHomepage(ctx) {
  const { opts, base, perPageMs, record } = ctx;
  const home = await fetchPage(opts.fetchFn, base + '/', perPageMs, opts.timers);
  const homeHtml = home && home.body ? String(home.body) : '';
  const homeKlass = extract.pageContentClass(home ? home.status : 0, homeHtml);
  if (homeKlass !== 'content') record('homepage-not-content', base + '/ classified as "' + homeKlass + '"; no content asserted from it (C-031/C-038)');
  return { home, homeHtml, homeKlass };
}

// discoverFetchList(ctx, homeHtml, fetchXml, maxPages) -> the deduped, same-site, Tier-1-FIRST-then-capped
// fetch list (C-026). Links (homepage) and sitemap are discovered in PARALLEL (E-236); orderCandidates
// ranks by tier BEFORE the cap slice, so a Tier-1 legal page survives a cap smaller than the candidate
// count even when it was discovered last.
async function discoverFetchList(ctx, homeHtml, fetchXml, maxPages) {
  const { dom, base, accepted } = ctx;
  const [links, sitemap] = await Promise.all([
    Promise.resolve(homeHtml ? discover.discoverLinks(homeHtml, base, accepted) : []),
    discover.discoverSitemap(dom, accepted, fetchXml).catch(() => []),
  ]);
  return discover.orderCandidates(base + '/', [...links, ...sitemap], accepted, maxPages);
}

// followFooterDocuments(ctx, homeHtml, pages) -> the documents-lane result. Skipped (empty) when
// document-following is disabled or nothing readable was crawled; otherwise footer-linked policy documents
// are followed and read honestly (C-033, evidence/documents).
async function followFooterDocuments(ctx, homeHtml, pages) {
  const { opts, base, accepted, perPageMs, record } = ctx;
  const empty = { documents: [], unparsed: [], unparsedClasses: new Set(), notes: [] };
  if (opts.followDocuments === false || !pages.length) return empty;
  return collectDocuments(footerLinks(homeHtml, base, accepted),
    { fetchFn: opts.fetchFn, deadlineMs: perPageMs, timers: opts.timers, log: record });
}

// crawl(domain, opts) -> the evidence bundle. Thin orchestrator: resolve budgets, fetch the homepage,
// discover links + sitemap in parallel, order Tier-1-first then cap, fetch the corpus in parallel, follow
// footer documents, and assemble the corpus + coverage report.
async function crawl(domain, opts = {}) {
  const dom = normaliseDomain(domain);
  if (!dom || !dom.includes('.')) throw new Error('crawl: a fetchable domain (with a public suffix) is required, got ' + JSON.stringify(domain));
  if (typeof opts.fetchFn !== 'function') throw new Error('crawl: opts.fetchFn is required (all network is dependency-injected)');
  const { notes, record } = makeRecorder(opts);
  const { cap, maxPages, width, deadlineMs, perPageMs } = resolveBudgets(opts);
  const base = 'https://' + dom;
  const homeUrl = base + '/';
  const accepted = safeFetch.acceptedSiteSet(dom);
  const fetchXml = typeof opts.fetchXml === 'function' ? opts.fetchXml : makeFetchXml(opts.fetchFn, perPageMs, opts.timers);
  const ctx = { opts, dom, base, accepted, perPageMs, record };

  const { home, homeHtml, homeKlass } = await fetchHomepage(ctx);
  const fetchList = await discoverFetchList(ctx, homeHtml, fetchXml, maxPages);

  const results = await runPool(fetchList, width, deadlineMs,
    (u) => (u === homeUrl ? Promise.resolve(home) : fetchPage(opts.fetchFn, u, perPageMs, opts.timers)), opts.now);
  const { pages, truncated, telemetry } = accumulateCorpus(fetchList, results, cap);
  if (truncated) record('corpus-truncated', 'a page exceeded the ' + cap + '-char corpus cap; absence claims on it demote to needs-review (C-024)');

  const footerText = extract.extractFooterText(homeHtml);
  const docResult = await followFooterDocuments(ctx, homeHtml, pages);

  const unreachable = pages.length === 0;
  const corpus = { pages, footerText: footerText || undefined };
  return {
    domain: dom,
    corpus,
    unreachable,
    reason: blockReason(home, homeKlass, pages.length),
    documents: { records: docResult.documents, unparsed: docResult.unparsed },
    coverage: buildCoverage(pages, opts, truncated, docResult.unparsedClasses),
    telemetry: { ...telemetry, pages_captured: pages.length, truncated, via: unreachable ? 'none' : 'direct' },
    notes,
  };
}

module.exports = {
  crawl, resolveCap, normaliseDomain, accumulateCorpus, contentPageFrom, footerLinks, blockReason,
  resolveBudgets, makeRecorder, fetchHomepage, discoverFetchList, followFooterDocuments,
};
===== pool.js =====
'use strict';
/**
 * pool.js - the E-236 parallel primitive and the Rule 9 hard-deadline wrapper.
 *
 * E-236 restored a 43s crawl to 6.9s with identical accuracy by removing the IDLING, not the work: I/O-
 * bound page fetches run in a bounded-concurrency pool with a wall-clock deadline that is a CAP (it stops
 * STARTING new work past the deadline), never a floor (Constitution Rule 8 - no Math.max, no minimum wait).
 * The pool width comes from the caller; nothing here widens or floors it.
 *
 * Rule 9: every external step is wrapped in a hard Promise.race deadline, so a slow dependency degrades
 * the crawl (a null slot) and never hangs it (the 752s stuck-Chromium class). Timers are INJECTABLE so
 * node:test drives this deterministically with no real wall-clock wait.
 */

// withDeadline(factory, ms, timers) -> a promise that settles with factory()'s value, or REJECTS once
// `ms` elapses, whichever is first. timers defaults to the globals; a test injects a fake pair. The
// timer is always cleared so a resolved factory never leaves a dangling handle keeping the process alive.
function withDeadline(factory, ms, timers) {
  const T = timers || { setTimeout, clearTimeout };
  let timer = null;
  const deadline = new Promise((_resolve, reject) => {
    timer = T.setTimeout(() => reject(new Error('deadline exceeded after ' + ms + 'ms')), ms);
    if (timer && typeof timer.unref === 'function') timer.unref();
  });
  return Promise.race([Promise.resolve().then(factory), deadline])
    .finally(() => { if (timer) T.clearTimeout(timer); });
}

// runPool(items, width, deadlineMs, fn, now) -> results aligned to `items` (null where a fetch failed or
// the wall-clock deadline was reached before that item STARTED). `now` is injectable (defaults to
// Date.now) so a test can prove the deadline is a cap: advance the clock past deadlineMs and the pool
// stops starting work, leaving the un-started tail null - it never blocks and never floors.
async function runPool(items, width, deadlineMs, fn, now) {
  const clock = typeof now === 'function' ? now : Date.now;
  const out = new Array(items.length);
  let idx = 0;
  const start = clock();
  async function worker() {
    for (;;) {
      const i = idx++;
      if (i >= items.length) return;
      if (clock() - start > deadlineMs) { out[i] = null; continue; } // CAP: never START past the deadline
      try { out[i] = await fn(items[i], i); }
      catch (e) { out[i] = null; /* FAIL-OPEN: one page's failure degrades to a null slot and the crawl continues (E-236 tolerance); the null is visible to the caller's telemetry, not swallowed silently. */ }
    }
  }
  const lanes = items.length === 0 ? 0 : Math.min(width, items.length);
  await Promise.all(Array.from({ length: lanes }, worker));
  return out;
}

module.exports = { withDeadline, runPool };

===== crawl.test.js =====
'use strict';
// crawl.test.js - the crawler orchestrator, driven entirely offline (every fetch is injected).
//
// The load-bearing proof is TIER-1-BEFORE-CAP (caution.md C-026): Tier-1 legal pages are ordered ahead of
// commercial pages BEFORE the page cap is applied, so a legal page discovered LAST still survives a cap
// smaller than the candidate count, and a commercial page discovered FIRST is shed. The two seeded C-027
// (query-string) and C-031 (login-wall) fixtures are replayed here too.

const test = require('node:test');
const assert = require('node:assert');
const fs = require('node:fs');
const path = require('node:path');

const { crawl, normaliseDomain } = require('./crawl.js');
const discover = require('./discover.js');
const { classify } = require('./coverage-contract.js');

const FIX = path.join(__dirname, '..', '..', 'eval', 'calibration-known-bad', 'fixtures');
function loadFixture(name) { return JSON.parse(fs.readFileSync(path.join(FIX, name), 'utf8')); }

// fetchFnFromPages(pages) -> { fetchFn, calls }. Serves 200 HTML for a known URL, 404 otherwise; `calls`
// records every fetched URL in order, so a test can inspect the crawl's real fetch sequence.
function fetchFnFromPages(pages) {
  const calls = [];
  const fetchFn = (url) => {
    calls.push(url);
    if (Object.prototype.hasOwnProperty.call(pages, url)) {
      return Promise.resolve({ ok: true, status: 200, body: pages[url], finalUrl: url, contentType: 'text/html' });
    }
    return Promise.resolve({ ok: false, status: 404, body: '', finalUrl: url });
  };
  return { fetchFn, calls };
}

// Deterministic, fast crawl opts: a constant clock so the wall-clock cap never trips, width 1 so the fetch
// order equals the ordered fetch list (the ordering proof reads that order directly).
function crawlOpts(fetchFn, extra = {}) {
  return { fetchFn, now: () => 0, width: 1, deadlineMs: 5000, perPageMs: 5000, ...extra };
}

const isInfra = (u) => /\/robots\.txt$/.test(u) || /sitemap/i.test(u);

test('TIER-1-BEFORE-CAP: a legal page discovered LAST beats commercial pages discovered first, before the cap', async () => {
  const home = [
    '<html><head><title>Order Test Ltd</title></head><body>',
    '<h1>Order Test</h1><p>We provide professional services to businesses across the United Kingdom.</p>',
    '<nav>',
    '<a href="/services">Services</a>',
    '<a href="/about">About</a>',
    '<a href="/pricing">Pricing</a>',
    '<a href="/team">Our team</a>',
    '<a href="/modern-slavery-statement">Modern slavery statement</a>', // TIER-1, listed LAST in the DOM
    '</nav>',
    '<footer>Order Test Ltd, company number 01234567.</footer>',
    '</body></html>',
  ].join('');
  const commercial = ['services', 'about', 'pricing', 'team'];
  const pages = { 'https://ordertest.example/': home };
  for (const c of commercial) {
    pages['https://ordertest.example/' + c] = '<html><title>' + c + '</title><body><h1>' + c + '</h1><p>Our ' + c + ' information for clients and customers across the country.</p></body></html>';
  }
  pages['https://ordertest.example/modern-slavery-statement'] = '<html><title>Modern slavery statement</title><body><h1>Modern slavery statement</h1><p>Our statement under the Modern Slavery Act describing the steps we take to prevent slavery in our supply chains.</p></body></html>';

  const { fetchFn, calls } = fetchFnFromPages(pages);
  // cap 13 = homepage + 11 Tier-1 (10 guessed policy paths + the discovered modern-slavery page) + exactly
  // ONE Tier-2 slot. Because Tier ranking happens before the cap slice, the single surviving Tier-2 is the
  // FIRST commercial in discovery order (/services); the rest are shed even though they were discovered
  // before the Tier-1 modern-slavery page.
  const bundle = await crawl('ordertest.example', crawlOpts(fetchFn, { maxPages: 13 }));

  assert.equal(bundle.unreachable, false);
  const fetched = calls.filter((u) => !isInfra(u));
  const idx = (u) => fetched.indexOf(u);

  // 1. The Tier-1 page discovered LAST survived the cap and was fetched.
  assert.ok(idx('https://ordertest.example/modern-slavery-statement') !== -1,
    'the Tier-1 legal page discovered last must survive the cap (ordering precedes accounting)');
  // 2. Three of the four commercial pages, discovered BEFORE the legal page, were shed by the cap.
  for (const c of ['about', 'pricing', 'team']) {
    assert.equal(idx('https://ordertest.example/' + c), -1,
      '/' + c + ' (Tier-2) must be dropped by the cap while the DOM-later Tier-1 page survives');
  }
  // 3. The one surviving commercial page (/services) is fetched AFTER the legal page - Tier-1 before
  //    commercial - even though /services was discovered first.
  assert.ok(idx('https://ordertest.example/services') !== -1, '/services is the one surviving Tier-2 at cap 13');
  assert.ok(idx('https://ordertest.example/modern-slavery-statement') < idx('https://ordertest.example/services'),
    'the Tier-1 legal page is fetched before the commercial page, though discovered later');
  // 4. Generalised: in the fetch order, every Tier-1 page precedes every Tier-2 page.
  const nonHome = fetched.filter((u) => u !== 'https://ordertest.example/');
  const lastTier1 = nonHome.map(discover.classifyTier).lastIndexOf('tier1');
  const firstTier2 = nonHome.map(discover.classifyTier).indexOf('tier2');
  assert.ok(firstTier2 === -1 || firstTier2 > lastTier1, 'no Tier-2 page is fetched before any Tier-1 page');
});

test('C-027: a query-string policy page is crawled and covers the privacy class (p3-crawl-querystring)', async () => {
  const fx = loadFixture('p3-crawl-querystring.json');
  const { fetchFn } = fetchFnFromPages(fx.pages);
  const bundle = await crawl(fx.domain, crawlOpts(fetchFn, { maxPages: fx.maxPages, sector: 'law-firms' }));

  assert.equal(bundle.unreachable, !fx.expect.reachable);
  for (const u of fx.expect.crawledIncludes) {
    assert.ok(bundle.corpus.pages.some((p) => p.url === u), 'a query-string URL must be crawled, not dropped: ' + u);
  }
  if (fx.expect.privacyClassCovered) {
    assert.ok(bundle.corpus.pages.some((p) => classify(p) === 'privacy'), 'the query-string privacy page must count toward privacy coverage');
    assert.ok(bundle.coverage.site.fetched_classes.includes('privacy'));
  }
});

test('C-031: a login-walled homepage stays UNREACHABLE, nothing asserted (p3-crawl-login-reachable)', async () => {
  const fx = loadFixture('p3-crawl-login-reachable.json');
  const { fetchFn } = fetchFnFromPages(fx.pages);
  const bundle = await crawl(fx.domain, crawlOpts(fetchFn));

  assert.equal(bundle.unreachable, fx.expect.unreachable);
  assert.equal(bundle.reason, fx.expect.reason);
  assert.equal(bundle.corpus.pages.length, fx.expect.contentPages);
  assert.equal(bundle.telemetry.content, 0, 'a login wall is never content');
});

test('a fully 404 site is unreachable with an honest reason, and asserts nothing', async () => {
  const { fetchFn } = fetchFnFromPages({});
  const bundle = await crawl('gone.example', crawlOpts(fetchFn));
  assert.equal(bundle.unreachable, true);
  assert.equal(bundle.reason, 'http_404');
  assert.deepEqual(bundle.corpus.pages, []);
});

test('a reachable site returns a corpus with stripped text, the footer surface, and telemetry', async () => {
  const pages = {
    'https://good.example/': '<html><head><title>Good Ltd</title></head><body><h1>Welcome</h1><p>We help clients with professional services every day of the week.</p><footer>Good Ltd, company number 07654321, registered in England.</footer></body></html>',
    'https://good.example/privacy': '<html><head><title>Privacy</title></head><body><h1>Privacy policy</h1><p>This policy explains how Good Ltd processes personal data under the UK GDPR and Data Protection Act 2018.</p></body></html>',
  };
  const { fetchFn } = fetchFnFromPages(pages);
  const bundle = await crawl('good.example', crawlOpts(fetchFn));
  assert.equal(bundle.unreachable, false);
  assert.ok(bundle.corpus.pages.length >= 2);
  assert.ok(/registered in England/.test(bundle.corpus.footerText), 'the footer disclosure surface is captured (C-034)');
  const home = bundle.corpus.pages.find((p) => p.url === 'https://good.example/');
  assert.ok(!/<script|<h1>/.test(home.text), 'corpus text is stripped visible text only (C-012)');
  assert.ok(bundle.telemetry.content >= 2 && bundle.telemetry.pages_captured >= 2);
});

test('crawl rejects an unfetchable domain and a missing fetchFn (fail loud, never a silent empty crawl)', async () => {
  const { fetchFn } = fetchFnFromPages({});
  await assert.rejects(crawl('not-a-domain', crawlOpts(fetchFn)), /fetchable domain/);
  await assert.rejects(crawl('good.example', { now: () => 0 }), /fetchFn is required/);
});

test('normaliseDomain routes through the safe-fetch host door (scheme/path/port/www parsed off)', () => {
  assert.equal(normaliseDomain('https://www.Example.co.uk/some/path?x=1'), 'example.co.uk');
  assert.equal(normaliseDomain('EXAMPLE.com:8443'), 'example.com');
  assert.equal(normaliseDomain(''), '');
});
===== pool.test.js =====
'use strict';
// pool.test.js - the E-236 parallel primitive and the Rule 8 / Rule 9 proofs.
//
// The load-bearing proof here is DEADLINE-AS-CAP (Constitution Rule 8): the pool's wall-clock deadline
// STOPS it starting new work, it never imposes a minimum wait. The clock is injected so the proof is
// deterministic and instant - a floor would reveal itself as work that runs (or a wait that elapses)
// after the deadline has already passed, and these tests assert neither happens.

const test = require('node:test');
const assert = require('node:assert');

const { withDeadline, runPool } = require('./pool.js');

// timers that never fire the deadline (records that the timer is cleared on settle, so no dangling handle).
function noFireTimers() {
  const state = { cleared: false };
  const timers = { setTimeout: () => ({ unref() {} }), clearTimeout: () => { state.cleared = true; } };
  return { timers, state };
}

// timers whose setTimeout fires its callback synchronously (the deadline wins the race immediately).
function immediateTimers() {
  return { setTimeout: (cb) => { cb(); return { unref() {} }; }, clearTimeout: () => {} };
}

// steppingClock(seq) -> a now() returning seq[0], seq[1], ... then the last value forever. Lets a test
// place the pool's clock reads exactly: read #1 is `start`, then one read per worker iteration.
function steppingClock(seq) {
  let i = 0;
  return () => seq[Math.min(i++, seq.length - 1)];
}

test('withDeadline: a factory that resolves in time yields its value and CLEARS the timer', async () => {
  const { timers, state } = noFireTimers();
  const v = await withDeadline(() => Promise.resolve(7), 100, timers);
  assert.equal(v, 7);
  assert.equal(state.cleared, true, 'the deadline timer must be cleared so no handle keeps the process alive');
});

test('withDeadline: the deadline REJECTS a factory that never settles (Promise.race, Rule 9)', async () => {
  await assert.rejects(
    withDeadline(() => new Promise(() => {}), 100, immediateTimers()),
    /deadline exceeded after 100ms/,
  );
});

test('withDeadline: a synchronously-throwing factory rejects with ITS error, not a timeout', async () => {
  const { timers } = noFireTimers();
  await assert.rejects(withDeadline(() => { throw new Error('boom'); }, 100, timers), /boom/);
});

test('runPool: within the deadline, every item runs and results align to the input order', async () => {
  const items = ['a', 'b', 'c', 'd'];
  const out = await runPool(items, 2, 1000, (u, i) => Promise.resolve(u + i), () => 0);
  assert.deepEqual(out, ['a0', 'b1', 'c2', 'd3']);
});

test('DEADLINE-AS-CAP: once the clock passes the deadline the pool STOPS starting work (no floor)', async () => {
  // width 1 -> one worker -> clock reads are: #1 start, then one per item. The clock is at 50ms for the
  // first item (runs) and jumps to 200ms (past the 100ms deadline) for the rest, so items b, c, d are
  // never STARTED - they degrade to null immediately, they do not wait out any minimum (Rule 8).
  const started = [];
  const now = steppingClock([0, 50, 200, 200, 200]);
  const out = await runPool(['a', 'b', 'c', 'd'], 1, 100,
    (u) => { started.push(u); return Promise.resolve(u.toUpperCase()); }, now);
  assert.deepEqual(started, ['a'], 'only the item started before the deadline ran; the tail was never started');
  assert.deepEqual(out, ['A', null, null, null], 'past-deadline items are null, not delayed to a floor');
});

test('DEADLINE-AS-CAP: a deadline already exceeded at start runs NOTHING (no minimum-work floor)', async () => {
  const started = [];
  // start reads 0; every item check reads 500 (> the 100ms deadline) -> all null, fn never called.
  const now = steppingClock([0, 500, 500, 500]);
  const out = await runPool(['a', 'b', 'c'], 1, 100, (u) => { started.push(u); return Promise.resolve(u); }, now);
  assert.deepEqual(started, [], 'no item is started once the deadline is already past - the pool never floors up to N');
  assert.deepEqual(out, [null, null, null]);
});

test('runPool: one item throwing degrades to a null slot; the pool continues (FAIL-OPEN tolerance)', async () => {
  const out = await runPool(['a', 'b', 'c'], 3, 1000,
    (u) => (u === 'b' ? Promise.reject(new Error('flaky')) : Promise.resolve(u)), () => 0);
  assert.deepEqual(out, ['a', null, 'c']);
});

test('runPool: concurrency never exceeds width', async () => {
  let inFlight = 0;
  let peak = 0;
  const fn = async (u) => {
    inFlight++; peak = Math.max(peak, inFlight);
    await Promise.resolve(); await Promise.resolve();
    inFlight--;
    return u;
  };
  const out = await runPool(['a', 'b', 'c', 'd', 'e', 'f'], 2, 1000, fn, () => 0);
  assert.equal(out.length, 6);
  assert.ok(peak <= 2, 'at most `width` fetches in flight at once, got peak ' + peak);
});

test('runPool: an empty item list opens no lanes and returns []', async () => {
  let called = false;
  const out = await runPool([], 8, 1000, () => { called = true; return Promise.resolve(1); }, () => 0);
  assert.deepEqual(out, []);
  assert.equal(called, false);
});

