604	// pagesOfClass(pages, pageClass) -> the pages whose path classifies to pageClass; all pages for 'any'.
605	// Uses coverage-contract.classify (anchored path segments, never substrings - C-044), the one door for
606	// page-class so the surface propose scans matches the surface coverage judged (C-035).
607	function pagesOfClass(pages, pageClass) {
608	  if (!pageClass || pageClass === 'any') return pages;
609	  return pages.filter((p) => coverageContract.classify(p.url) === pageClass);
610	}
611	// surfaceTextForPresence(spec, pages, footer) -> the surface text a REQUIRED-content check scans, plus
612	// the pages it covers. The footer is ALWAYS included, never scanned exclusively: it is an ADDITIONAL
613	// mandatory statutory-disclosure surface (C-034), so a disclosure in the body OR the footer counts as
614	// present. Scanning the footer alone would read a body disclosure as "missing" (the false-positive this
615	// fixes). 'raw_html' is unreadable in the stripped bundle; the interlock abstains before reaching here.
616	function surfaceTextForPresence(detectionSpec, pages, footer) {
617	  const scoped = pagesOfClass(pages, detectionSpec.page_class);
618	  const text = scoped.map((p) => p.text).concat(footer ? [footer] : []).join('\n');
619	  const coveredPages = scoped.map((p) => p.url).concat(footer ? ['(footer)'] : []);
620	  return { text, coveredPages };
621	}
622	
623	// ── pattern matching ───────────────────────────────────────────────────────────────────────────────
624	// pathHasSegment(url, seg) -> true when the url path contains seg ('/xxx') as a WHOLE segment (anchored,
625	// never a substring - C-044). matchUrlPath scans every page for the url-path pattern.
626	function pathHasSegment(url, seg) {
627	  let path;
628	  try { path = new URL(url).pathname.toLowerCase(); }
629	  catch (_err) {
630	    // FAIL-OPEN: a non-URL is matched as a raw path, never crashes the scan.
631	    path = String(url || '').toLowerCase();
632	  }
633	  const norm = ('/' + path.replace(/^\/+/, '')).replace(/\/+$/, '') + '/';
634	  return norm.includes(seg.toLowerCase() + '/') || norm.includes(seg.toLowerCase() + '-');
635	}
636	function matchUrlPath(value, pages) {
