638	}
639	// patternMatchesText(pattern, text) -> does a text pattern (anchored-regex or token-set) match `text`.
640	function patternMatchesText(pattern, text) {
641	  const re = spec.compileRegex(pattern);
642	  return re ? re.test(text) : false;
643	}
644	// requiredContentPresent(detectionSpec, surfaceText, pages) -> is ANY pattern satisfied (the lenient
645	// "present" check for a REQUIRED disclosure: a partial or differently-worded disclosure still counts as
646	// present, so the absence-breach fires only on total silence - the C-024 false-missing guard).
647	function requiredContentPresent(detectionSpec, surfaceText, pages) {
648	  for (const pattern of detectionSpec.patterns) {
649	    if (pattern.kind === 'url-path') { if (matchUrlPath(pattern.value, pages)) return true; continue; }
650	    if (patternMatchesText(pattern, surfaceText)) return true;
651	  }
652	  return false;
653	}
654	// prohibitedHitInSentence(detectionSpec, sentence) -> the first pattern that matches WHOLLY within one
655	// sentence (a scattered token-set across the page is not a single prohibited claim), or null.
656	function prohibitedHitInSentence(detectionSpec, sentence) {
657	  for (const pattern of detectionSpec.patterns) {
