659	    if (patternMatchesText(pattern, sentence)) return pattern;
660	  }
661	  return null;
662	}
663	
664	// findProhibitedQuote(detectionSpec, pages) -> { page_url, quote, guardedOnly }. Scans visible prose
665	// sentence by sentence; a carrier sentence must be genuine prose (C-089), not negated (C-048) and not a
666	// customer review (C-090). guardedOnly signals a match existed but every carrier was guarded away (a
667	// compliant self-declaration), so the abstention can be recorded rather than silent.
668	function findProhibitedQuote(detectionSpec, pages) {
669	  let sawGuarded = false;
670	  for (const page of pages) {
671	    for (const sentence of spec.splitSentences(page.text)) {
672	      if (!prohibitedHitInSentence(detectionSpec, sentence)) continue;
673	      if (spec.isNegated(sentence) || spec.looksLikeReview(sentence)) { sawGuarded = true; continue; }
674	      if (!spec.isProse(sentence)) continue;
675	      return { page_url: page.url, quote: sentence, guardedOnly: false };
676	    }
677	  }
678	  return { page_url: null, quote: null, guardedOnly: sawGuarded };
679	}
680	
681	// ── candidate builders ─────────────────────────────────────────────────────────────────────────────
682	function candidate(detectionSpec, kind, artifact, pageUrl, confidence) {
683	  return {
684	    record_id: detectionSpec.record_id,
685	    duty_idx: detectionSpec.duty_idx,
686	    evidence_type: detectionSpec.evidence_type,
687	    kind,
688	    artifact,
689	    page_url: pageUrl,
690	    confidence_hint: confidence,
691	    suppressed_reason: null,
692	  };
693	}
694	function suppressed(detectionSpec, kind, reason) {
695	  return {
696	    record_id: detectionSpec.record_id,
697	    duty_idx: detectionSpec.duty_idx,
698	    evidence_type: detectionSpec.evidence_type,
699	    kind,
700	    artifact: null,
701	    page_url: null,
702	    confidence_hint: null,
703	    suppressed_reason: reason,
704	  };
705	}
706	
707	// ── evaluators (one per evidence_type; each returns a candidate, a suppressed record, or null) ──────
708	
709	// evalPresenceBreach: an 'absence' obligation (PROHIBITED content). A hit in a clean visible sentence is
710	// a presence-breach with the verbatim quote as artifact (confidence strong). If every hit was negated /
711	// a review, record the abstention. No hit -> clean pass (null).
712	function evalPresenceBreach(detectionSpec, pages) {
713	  if (!detectionSpec.patterns.length) return null;
714	  const found = findProhibitedQuote(detectionSpec, pages);
715	  if (found.quote) {
716	    const artifact = { type: 'quote', text: found.quote, surface: detectionSpec.surface };
717	    return candidate(detectionSpec, KIND.PRESENCE_BREACH, artifact, found.page_url, 'strong');
718	  }
719	  if (found.guardedOnly) return suppressed(detectionSpec, KIND.PRESENCE_BREACH, 'all-matches-negated-or-review (compliant self-declaration or testimonial, C-048/C-090)');
720	  return null;
721	}
722	
723	// absenceInterlock(detectionSpec, bundle, coverageState) -> a suppression reason, or null when the
724	// coverage interlock is fully satisfied (C-024/C-025/C-026/C-036). Fail-closed: any doubt suppresses.
725	function absenceInterlock(detectionSpec, bundle, coverageState) {
726	  if (coverageState !== 'covered') return 'coverage ' + coverageState + ' for this rule; an absence claim needs a proven page-class (C-029)';
727	  if (detectionSpec.surface === 'raw_html') return 'required mechanism lives in raw HTML, unreadable in the stripped corpus; abstained rather than fabricate a missing-mechanism breach (C-036/C-032)';
728	  if (detectionSpec.surface === 'footer' && !footerOf(bundle)) return 'no footer surface was captured; a registration-disclosure absence cannot be asserted (C-034)';
729	  if (pagesOf(bundle).length < MIN_PAGES_FOR_ABSENCE) return 'corpus below the ' + MIN_PAGES_FOR_ABSENCE + '-page floor for an absence claim (C-025)';
730	  if (isTruncated(bundle)) return 'corpus was truncated; the required content may sit past the cut, so the absence claim is demoted (C-024)';
731	  return null;
732	}
733	
734	// evalAbsenceBreach: a 'presence' obligation (REQUIRED content). If the content is present -> clean pass.
735	// If absent, the interlock decides: satisfied -> an absence-breach with a coverage_proof artifact
736	// (confidence moderate); unsatisfied -> a recorded suppression.
737	function evalAbsenceBreach(detectionSpec, bundle, coverageState) {
738	  if (!detectionSpec.patterns.length) return null;
739	  const pages = pagesOf(bundle);
740	  const surface = surfaceTextForPresence(detectionSpec, pages, footerOf(bundle));
741	  if (requiredContentPresent(detectionSpec, surface.text, pages)) return null; // present -> no breach
742	  const block = absenceInterlock(detectionSpec, bundle, coverageState);
743	  if (block) return suppressed(detectionSpec, KIND.ABSENCE_BREACH, block);
744	  const artifact = {
745	    type: 'coverage_proof',
746	    page_class: detectionSpec.page_class,
747	    surface: detectionSpec.surface,
748	    pages_checked: surface.coveredPages,
749	    searched_patterns: detectionSpec.patterns.map(patternSummary),
750	  };
751	  return candidate(detectionSpec, KIND.ABSENCE_BREACH, artifact, null, 'moderate');
752	}
753	function patternSummary(pattern) {
754	  if (pattern.kind === 'token-set') return { kind: pattern.kind, tokens: pattern.value.tokens, mode: pattern.value.mode };
755	  return { kind: pattern.kind, value: pattern.value };
756	}
757	
758	// specTokens(detectionSpec) -> the flat set of lane-routing tokens a behavioural/register spec carries.
759	function specTokens(detectionSpec) {
760	  const out = new Set();
761	  for (const p of detectionSpec.patterns) {
762	    if (p.kind === 'token-set') for (const t of p.value.tokens) out.add(String(t).toLowerCase());
763	  }
764	  return out;
765	}
766	// obligationConcerns(detectionSpec, obsKind) -> does this behavioural obligation concern an observation
767	// of this kind (token intersection with the generic concept set); gates C-039/C-042 to consent duties.
768	function obligationConcerns(detectionSpec, obsKind) {
769	  const concepts = OBSERVATION_CONCEPTS[obsKind] || [];
770	  const tokens = specTokens(detectionSpec);
771	  return concepts.some((c) => tokens.has(c) || [...tokens].some((t) => t.includes(c)));
772	}
773	
774	// laneRan(browser) -> true only when the browser lane definitively ran; laneReason gives the recorded
775	// non-run reason (C-041: an evidence lane's absence is visible, never silent).
776	function laneRan(browser) {
777	  return Boolean(browser && browser.lane && browser.lane.ran === true);
778	}
779	function laneReason(browser) {
780	  return (browser && browser.lane && browser.lane.reason) || 'browser lane did not run';
781	}
782	// observedCandidates(detectionSpec, observed) -> a behavioural candidate per observation this obligation
783	// concerns (C-039: a pre-consent cookie set is a completed observed breach with the event as artifact).
784	function observedCandidates(detectionSpec, observed) {
785	  const out = [];
786	  for (const ev of (Array.isArray(observed) ? observed : [])) {
787	    if (!ev || !ev.kind || !obligationConcerns(detectionSpec, ev.kind)) continue;
788	    out.push(candidate(detectionSpec, KIND.BEHAVIOURAL, { type: 'network_event', ...ev }, ev.host || ev.url || null, 'strong'));
789	  }
790	  return out;
791	}
792	// brokenControlCandidate(detectionSpec, cc) -> a behavioural candidate when a found consent control is
793	// unhealthy on a consent-concerned obligation (C-042: a broken control is itself a finding class), else null.
794	function brokenControlCandidate(detectionSpec, cc) {
795	  if (!cc || cc.found !== true || cc.healthy !== false) return null;
796	  if (!obligationConcerns(detectionSpec, 'consent_control_broken')) return null;
797	  const artifact = { type: 'network_event', kind: 'consent_control_broken', url: cc.url || null, healthy: false };
798	  return candidate(detectionSpec, KIND.BEHAVIOURAL, artifact, cc.url || null, 'strong');
799	}
800	// evalBehavioural: consume bundle.browser. The lane not running is a recorded suppression (C-041).
801	function evalBehavioural(detectionSpec, bundle) {
802	  const browser = bundle && bundle.browser;
803	  if (!laneRan(browser)) return [suppressed(detectionSpec, KIND.BEHAVIOURAL, 'browser lane unavailable: ' + laneReason(browser) + ' (C-041)')];
804	  const out = observedCandidates(detectionSpec, browser.observed);
805	  const broken = brokenControlCandidate(detectionSpec, browser.consentControl);
806	  if (broken) out.push(broken);
807	  return out;
808	}
809	
810	// registerTargetFor(detectionSpec, record, keys) -> the bundle register key this record's register duty
811	// checks, derived from the record's OWN id/citation/register_url tokens against the bundle's OWN register
812	// keys (data-driven; no regulator name is authored here - Rule 2), or null when unresolved.
813	function registerTargetFor(record, keys) {
814	  const blob = [record && record.id, record && record.regulator && record.regulator.register_url,
815	    record && record.citation && record.citation.url].filter(Boolean).join(' ').toLowerCase();
816	  return keys.find((k) => blob.includes(String(k).toLowerCase())) || null;
817	}
818	// evalRegister: consume bundle.registers. A present matched row is compliant (no candidate). A DEFINITIVE
819	// no_match note (C-004) is a weak candidate carrying that note as its register_row artifact. Any other
820	// state (no target resolvable, a degraded/skipped lane, no note at all) is a recorded suppression.
821	function evalRegister(detectionSpec, bundle, record) {
822	  const registers = (bundle && bundle.registers) || {};
