824	  const notes = Array.isArray(registers.notes) ? registers.notes : [];
825	  const noteKeys = notes.map((n) => n && n.register).filter(Boolean);
826	  const target = registerTargetFor(record, [...new Set([...keys, ...noteKeys])]);
827	  if (!target) return suppressed(detectionSpec, KIND.REGISTER, 'no register lane resolvable for this record (unregistered lane / no lookup)');
828	  if (registers[target]) return null; // a matched row is present -> compliant on this duty
829	  const note = notes.find((n) => n && n.register === target);
830	  if (note && note.kind === 'no_match') {
831	    return candidate(detectionSpec, KIND.REGISTER, { type: 'register_row', present: false, register: target, lane: 'no_match', note }, null, 'weak');
832	  }
833	  return suppressed(detectionSpec, KIND.REGISTER, 'register "' + target + '" not definitively checked (' + ((note && note.kind) || 'no note') + '); a no-match is required before a non-appearance claim (C-004)');
834	}
835	
836	// ── the router ──────────────────────────────────────────────────────────────────────────────────────
837	function recordsForIndex(catalogue) {
838	  if (Array.isArray(catalogue)) return catalogue;
839	  if (catalogue && Array.isArray(catalogue.records)) return catalogue.records;
840	  return [];
841	}
842	function recordIndex(catalogue) {
843	  const map = new Map();
844	  for (const r of recordsForIndex(catalogue)) if (r && r.id) map.set(r.id, r);
845	  return map;
846	}
847	
848	// evaluateSpec(detectionSpec, bundle, coverage, record) -> candidate[] for one spec (0..n). Exported for
849	// unit tests. A page-class-bearing spec whose coverage is 'screened' NEVER proposes (C-029), the hard
850	// block applied before any evidence is read.
851	function evaluateSpec(detectionSpec, bundle, coverage, record) {
852	  const coverageState = coverageStateFor(coverage, detectionSpec.record_id);
853	  if (detectionSpec.page_class !== null && coverageState === 'screened') {
854	    return [suppressed(detectionSpec, kindForType(detectionSpec.evidence_type), 'page-class coverage screened; a screened rule never proposes (C-029)')];
855	  }
856	  if (detectionSpec.evidence_type === 'absence') return listOf(evalPresenceBreach(detectionSpec, pagesOf(bundle)));
857	  if (detectionSpec.evidence_type === 'presence') return listOf(evalAbsenceBreach(detectionSpec, bundle, coverageState));
858	  if (detectionSpec.evidence_type === 'behavioural') return evalBehavioural(detectionSpec, bundle);
859	  if (detectionSpec.evidence_type === 'register') return listOf(evalRegister(detectionSpec, bundle, record));
860	  return [];
861	}
862	function kindForType(evidenceType) {
863	  if (evidenceType === 'absence') return KIND.PRESENCE_BREACH;
864	  if (evidenceType === 'presence') return KIND.ABSENCE_BREACH;
865	  if (evidenceType === 'behavioural') return KIND.BEHAVIOURAL;
866	  return KIND.REGISTER;
867	}
868	function listOf(x) { return x ? [x] : []; }
869	
870	// propose(bundle, catalogue, coverage) -> candidates[]. The public entry. Compiles the catalogue to
871	// DetectionSpecs in memory, then evaluates each. An unreadable (C-038) or non-English-gated (C-022)
872	// bundle asserts nothing at all.
873	function propose(bundle, catalogue, coverage) {
874	  if (isUnreadable(bundle) || isNonEnglishGated(bundle)) return [];
875	  const { specs } = spec.compileCatalogue(catalogue);
876	  const records = recordIndex(catalogue);
877	  const out = [];
878	  for (const detectionSpec of specs) {
879	    const record = records.get(detectionSpec.record_id) || null;
880	    for (const c of evaluateSpec(detectionSpec, bundle, coverage, record)) out.push(c);
881	  }
882	  return out;
883	}
884	
885	module.exports = {
886	  propose,
887	  evaluateSpec,
888	  KIND,
889	  MIN_PAGES_FOR_ABSENCE,
890	  // exported for tests + reuse (one door for the matchers)
891	  requiredContentPresent,
892	  findProhibitedQuote,
893	  registerTargetFor,
894	  coverageStateFor,
895	  absenceInterlock,
896	};
