}
function loadAdjudicateStage(rootDir) {
  const c = STAGE_CONTRACT.adjudicate;
  return loadOptionalModule(rootDir, c.relPath, c.exportName);
}

module.exports = {
  loadOptionalModule,
  loadProposeStage,
  loadVerifyStage,
  loadAdjudicateStage,
  STAGE_CONTRACT,
  REPO_ROOT,
};
